const fs=require("fs"),path=require("path");function checkBotStatus(){console.log("🤖 NFT Tracker Bot Status Check"),console.log("=".repeat(40));const{exec:exec}=require("child_process");exec('ps aux | grep "node index.js" | grep -v grep',((error,stdout,stderr)=>{if(stdout){console.log("✅ Bot is running");stdout.trim().split("\n").forEach((line=>{const parts=line.split(/\s+/),pid=parts[1],cpu=parts[2],mem=parts[3];console.log(`   PID: ${pid}, CPU: ${cpu}%, Memory: ${mem}%`)}))}else console.log("❌ Bot is not running")}));try{const config=require("./config");console.log("\n📋 Configuration:"),console.log(`   Scan interval: ${config.scanInterval/1e3/60} minutes`),console.log(`   CSV file: ${config.csvFile}`),console.log("   Discord enabled: "+(config.discord.botToken?"Yes":"No")),console.log("   OpenSea API key: "+(config.opensea.apiKey?"Set":"Not set"))}catch(error){console.log("❌ Error reading config:",error.message)}try{const config=require("./config"),lines=fs.readFileSync(config.csvFile,"utf8").trim().split("\n"),walletCount=lines.length-1;console.log(`\n👥 Wallets: ${walletCount} wallets loaded`),walletCount>0&&(console.log("   Wallets:"),lines.slice(1).forEach((line=>{const[address,name]=line.split(",");console.log(`   - ${name} (${address})`)})))}catch(error){console.log("❌ Error reading wallets:",error.message)}console.log("\n"+"=".repeat(40)),console.log("🔄 Bot will check for new events every 5 minutes"),console.log("📊 Only NEW events will be processed (no historical data)"),console.log("🎯 Tracking: Ethereum & Base chains"),console.log("💬 Discord notifications enabled")}checkBotStatus(),process.argv.includes("--monitor")&&(console.log("\n🔍 Starting continuous monitoring..."),setInterval(checkBotStatus,6e4));